import{_ as l,o as a,c as o,a5 as p}from"./chunks/framework.B5tqjWbr.js";const _=JSON.parse('{"title":"教程 0015：单相锁相环（phase-locked loop / PLL）入门","description":"","frontmatter":{"title":"教程 0015：单相锁相环（phase-locked loop / PLL）入门","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0015-single-phase-srf-pll.html","status":"learning","visibility":"public","summary":"Imported from 0015-single-phase-srf-pll.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0015-single-phase-srf-pll.md","filePath":"content/power/lessons/0015-single-phase-srf-pll.md","lastUpdated":null}'),t={name:"content/power/lessons/0015-single-phase-srf-pll.md"};function i(r,e,s,c,n,d){return a(),o("div",null,[...e[0]||(e[0]=[p(`<h1 id="教程-0015-单相锁相环-phase-locked-loop-pll-入门" tabindex="-1">教程 0015：单相锁相环（phase-locked loop / PLL）入门 <a class="header-anchor" href="#教程-0015-单相锁相环-phase-locked-loop-pll-入门" aria-label="Permalink to &quot;教程 0015：单相锁相环（phase-locked loop / PLL）入门&quot;">​</a></h1><p>中文主讲，一个概念，一个仿真任务：用同步旋转坐标系里的 q 轴误差，修正估算频率，让估算相位追上电网相位。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学模型和教学参数，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>同步旋转坐标系（synchronous reference frame / SRF）PLL 的核心想法是：拿自己估算出来的相位 <code>theta_hat</code> 建一个旋转坐标系，再看电网电压在这个坐标系里的q 轴误差（q-axis error / vq）。</p><p>如果 <code>vq</code> 不为 0，说明估算相位和真实电网相位没有对齐。用比例积分控制器（proportional-integral controller / PI）把 <code>vq</code> 变成估算频率（estimated frequency / f_est）的修正量，再积分得到新的相位。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）需要知道电网相位。前级功率因数校正（power factor correction / PFC）要让输入电流参考和电网电压同相；旁路切换要判断逆变输出和电网是否同步；逆变器跟随电网或旁路时也要相位和频率信息。</p><p>如果 PLL 错，相当于后面的控制都站在错误坐标系上。电流参考、功率方向、并联系统同步和旁路切换都会受影响。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>把 PLL 想成一个追着电网转的指针。指针慢了，电网相位跑到前面；指针快了，估算相位超过电网。<code>vq</code> 就像“偏左还是偏右”的误差信号。PI 控制器根据这个误差调快或调慢指针，直到指针和电网相位对齐。</p><pre><code>电网电压
vac

相位检测
vq = sin(theta_err)

PI滤波
omega_hat

相位积分
theta_hat

估算相位反馈到下一次相位检测
本节先看相位闭环，不展开双二阶广义积分器等工程增强结构
</code></pre><p>图 1：SRF-PLL 的最小控制链。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>theta_err = theta_grid - theta_hat vq = sin(theta_err) omega_hat = omega_nominal + Kp * vq + integral(Ki * vq) theta_hat[k+1] = theta_hat[k] + omega_hat * Ts</p><p>锁定附近 <code>sin(theta_err) ≈ theta_err</code>，所以 PLL 可以近似看作一个二阶闭环。<code>Kp</code> 和 <code>Ki</code> 决定它追得快不快、抖不抖；锁定带（lock band）则定义“相位误差已经足够小”的工程阈值。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\single_phase_srf_pll.py</p><p>脚本会生成并自动打开图；如果无法自动打开，会打印完整路径。图里包含电网电压、相位误差、锁定带、q 轴误差、估算频率和参数框。</p><pre><code>一个仿真任务
python simulations\\python\\single_phase_srf_pll.py --kp 80 --ki 3000 --output simulations\\results\\srf_pll_slow.png
</code></pre><p>python simulations\\python\\single_phase_srf_pll.py --kp 260 --ki 22000 --output simulations\\results\\srf_pll_fast.png</p><p>对比慢 PLL 和快 PLL：慢的相位误差收敛更慢，快的频率估算动作更激烈，也更容易把噪声带进去。</p><p>观察顺序：</p><ul><li><p>先看 60 ms 的相位阶跃位置。</p></li><li><p>看 <code>theta_err</code> 是否跳变后回到 ±5 度锁定带内。</p></li><li><p>看 <code>vq</code> 是否随着相位误差减小而回到 0 附近。</p></li><li><p>看 <code>f_est</code> 是否短时偏离 50 Hz，然后回到电网频率附近。</p></li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件里 PLL 通常在固定采样周期运行：</p><p>ADC voltage sample -&gt; scaling/filtering -&gt; phase detector, vq -&gt; PI loop filter -&gt; frequency limit -&gt; phase accumulator -&gt; sin/cos angle output</p><ul><li><p>输入电压需要滤波或幅值归一化，否则幅值变化和谐波会污染相位检测。</p></li><li><p>估算频率要限幅，避免采样异常时相位飞掉。</p></li><li><p>PLL 输出角度会被 PFC 电流参考、旁路同步和逆变控制复用。</p></li><li><p>锁定判据不能只看瞬时误差，要看一段时间内的相位误差和频率误差。</p></li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**PLL 只是过零检测。 **纠正：**过零检测只能粗略给相位点，PLL 是连续估算相位和频率的闭环。</p></li><li><p>**误解：**PLL 越快越好。 **纠正：**太快会把电网噪声、谐波和采样毛刺带进角度；太慢会跟不上频率和相位变化。</p></li><li><p>**误解：**PFC 不需要 PLL。 **纠正：**简单单相 PFC 可以直接用电压采样生成参考，但工程里仍常需要相位、频率、过零、同步和异常检测信息。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能解释 <code>vq</code> 为什么代表估算相位偏差。</p></li><li><p>能说明 <code>omega_hat</code> 如何由 nominal frequency、比例项和积分项组成。</p></li><li><p>能在图中指出 <code>vac</code>、<code>theta_err</code>、<code>vq</code>、<code>f_est</code> 和锁定带。</p></li><li><p>能解释相位阶跃后 <code>f_est</code> 为什么会短时升高。</p></li><li><p>能基于仿真图准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么 <code>theta_err</code> 回到 0 附近时，<code>vq</code> 也会回到 0 附近？</p></li><li><p>如果把 <code>Kp</code> 和 <code>Ki</code> 调得很大，图里的 <code>f_est</code> 会出现什么变化？</p></li><li><p>如果输入电网电压含 5 次谐波，PLL 角度可能会怎样受影响？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>single_phase_srf_pll.py</code> 看到 30 度相位阶跃后，<code>f_est</code> 会短时升高再回到 50 Hz。公司 UPS 的 PLL 锁定判据通常看相位误差、频率误差，还是两者都看？</p></li><li><p>图里 <code>Kp=180, Ki=12000</code> 能较快收敛。实际工程中 PLL 带宽通常如何选，PFC 和旁路同步会不会用不同带宽？</p></li><li><p>如果输入电压含谐波或采样噪声，公司平台是在 PLL 前加滤波，还是在 <code>vq</code> 误差后加滤波？</p></li></ul><p>**下一步：**继续 PLL，不急着进逆变器：先看频率偏差和谐波/噪声对锁相的影响。</p><p>关联：<a href="./0014-single-phase-pfc-average-controller.html">上一节：单相 PFC 平均控制链</a>；源稿：<code>concepts/control/single-phase-srf-pll.md</code>。</p><pre><code>上一节：教程 0014：单相功率因数校正（power factor correction / PFC）的平均控制链
下一节：教程 0016：单相锁相环（phase-locked loop / PLL）的带宽取舍
</code></pre>`,42)])])}const u=l(t,[["render",i]]);export{_ as __pageData,u as default};
